import sys
from collections import defaultdict

input_data = sys.stdin.buffer.read().split()
idx = 0

def rd():
    global idx
    v = input_data[idx]; idx+=1
    return int(v)

t = rd()
for _ in range(t):
    n, m = rd(), rd()
    x = [rd() for _ in range(n)]
    s = []
    for i in range(n):
        s.append(input_data[idx].decode()); idx+=1

    profile_to_questions = defaultdict(list)
    for j in range(m):
        prof = tuple(int(s[i][j]) for i in range(n))
        profile_to_questions[prof].append(j)

    profiles = list(profile_to_questions.keys())
    cap = {prof: len(profile_to_questions[prof]) for prof in profiles}

    r = [0]*n
    assignment = {}  # question -> value

    remaining = {prof: cap[prof] for prof in profiles}
    prof_values = defaultdict(list)

    for v in range(m, 0, -1):
        best_gain = -1
        best_prof = None
        for prof in profiles:
            if remaining[prof] == 0:
                continue
            gain = sum(abs(x[i] - r[i] - prof[i]*v) - abs(x[i]-r[i]) for i in range(n))
            if gain > best_gain:
                best_gain = gain
                best_prof = prof
        remaining[best_prof] -= 1
        for i in range(n):
            r[i] += best_prof[i]*v
        prof_values[best_prof].append(v)

    result = [0]*(m+1)
    for prof in profiles:
        vals = sorted(prof_values[prof])
        qs = profile_to_questions[prof]
        for j, q in enumerate(qs):
            result[q+1] = vals[j]

    print(*result[1:])

